### Quest Types (src/shared/types.ts — add)
```typescript
export interface Quest {
  id: string;
  name: string;
  description: string;
  giver: string;
  location: string;
  stages: Array<{ id: string; text: string }>;
  objectives: QuestObjective[];
  rewards: { gold?: number; xp?: number; items?: string[] };
  prerequisite?: string | null;
}

export interface QuestObjective {
  type: 'flag' | 'item' | 'kill' | 'reach' | 'turnin';
  flag?: string;
  itemId?: string;
  count?: number;
  monsterId?: string;
  mapId?: string;
  x?: number;
  y?: number;
  stageAdvance: string;
}

export interface QuestState {
  questId: string;
